
// Language-aware currency display.
// Arabic page  → symbol BEFORE amount, forced visually as د.ل400.00 in RTL containers.
// English page → amount + ' ' + uppercase ISO code, e.g. 400.00 LYD.
const __AR_CUR_RX=/[\u0600-\u06FF\u0750-\u077F\uFB50-\uFDFF\uFE70-\uFEFF]/;
const __SYM2CODE={};
const __AR_CUR_SYMBOL_BY_CODE={AED:'د.إ',BHD:'د.ب',DZD:'دج',EGP:'ج.م',IQD:'ع.د',JOD:'د.أ',KWD:'د.ك',LBP:'ل.ل',LYD:'د.ل',MAD:'د.م.',MRU:'أوقية',OMR:'ر.ع.',QAR:'ر.ق',SAR:'ر.س',SDG:'ج.س.',SYP:'ل.س',TND:'د.ت',YER:'ر.ي'};
function __stripDirMarks(s){return(!s||typeof s!=='string')?s:s.replace(/[\u202A-\u202E\u2066-\u2069]/g,'');}
function __normalizeCurSym(s,code){const r=__stripDirMarks(s||'');const cc=(code||'').toString().toUpperCase();if(cc&&__AR_CUR_SYMBOL_BY_CODE[cc])return __AR_CUR_SYMBOL_BY_CODE[cc];if(r==='ل.د')return'د.ل';if(r==='.د.ب')return'د.ب';return r;}
function __rawSym(s,code){return __normalizeCurSym(s,code);}
function __wrapArSym(s,code){const cc=(code||'').toString().toUpperCase();const r=__rawSym(s,cc);if(cc&&r){__SYM2CODE[r]=cc;const old=__stripDirMarks(s||'');if(old)__SYM2CODE[old]=cc;}return r;}
function __money(n,sym,code){const a=parseFloat(n||0).toFixed(2);const cc=(code||__SYM2CODE[__stripDirMarks(sym||'')]||'').toString().toUpperCase();const r=__rawSym(sym||'£',cc);const isAr=(typeof document!=='undefined'&&document.documentElement.lang==='ar');if(isAr){return '\u202D'+r+a+'\u202C';}return cc?(a+' '+cc):(r+a);}
if(typeof window!=='undefined'){window.__money=__money;window.__rawSym=__rawSym;}

/* Charts */
const __AR_LBL={Sun:'الأحد',Mon:'الإثنين',Tue:'الثلاثاء',Wed:'الأربعاء',Thu:'الخميس',Fri:'الجمعة',Sat:'السبت',Jan:'يناير',Feb:'فبراير',Mar:'مارس',Apr:'أبريل',May:'مايو',Jun:'يونيو',Jul:'يوليو',Aug:'أغسطس',Sep:'سبتمبر',Oct:'أكتوبر',Nov:'نوفمبر',Dec:'ديسمبر'};
const __ar=()=>document.documentElement.lang==='ar';
const __tlbl=v=>(__ar()&&__AR_LBL[v])?__AR_LBL[v]:v;
window.addEventListener('lateen-lang',()=>{try{if(typeof loadProducts==='function')loadProducts();if(typeof loadOrders==='function')loadOrders();if(typeof buildMainChart==='function')buildMainChart();if(typeof renderVariantGroups==='function')renderVariantGroups();if(typeof refreshProfile==='function')refreshProfile();}catch(e){}});
const chartData={revenue:{D:{labels:[],sub:[],values:[]},M:{labels:[],sub:[],values:[]},Y:{labels:[],sub:[],values:[]}},pieces:{D:{labels:[],sub:[],values:[]},M:{labels:[],sub:[],values:[]},Y:{labels:[],sub:[],values:[]}}};
const analyticsData={D:{ok:0,fail:0},M:{ok:0,fail:0},Y:{ok:0,fail:0}};
let currentMetric='revenue',currentPeriod='D',mainChart,ringChart;
const __VIS={D:7,M:6,Y:6};
function __pad(n){return n<10?'0'+n:''+n;}
function __ddmmyyyy(d){return __pad(d.getDate())+'/'+__pad(d.getMonth()+1)+'/'+d.getFullYear();}
function buildMainChart(){
  if(mainChart){try{mainChart.destroy();}catch(e){}mainChart=null;}
  const canvas=document.getElementById('mainChart');if(!canvas||typeof Chart==='undefined')return;
  const d=chartData[currentMetric][currentPeriod];
  const labels=d.labels.map(v=>__tlbl(v));
  const subs=d.sub||[];
  const n=d.values.length;const vis=Math.min(__VIS[currentPeriod]||7,n);
  const maxIdx=n-1;const minIdx=Math.max(0,n-vis);
  const hasZoom=!!(Chart.registry&&Chart.registry.plugins&&(()=>{try{return Chart.registry.plugins.get('zoom');}catch(e){return false;}})());
  const __curRange=vis;
  const __guardZoomOut=({chart})=>{const sx=chart.scales.x;if((sx.max-sx.min)>=__curRange){sx.options.min=minIdx;sx.options.max=maxIdx;chart.update('none');return false;}};
  const zoomOpts=hasZoom?{zoom:{pan:{enabled:true,mode:'x',threshold:10},zoom:{wheel:{enabled:true,speed:0.05,modifierKey:null},pinch:{enabled:true},mode:'x',onZoom:__guardZoomOut,onZoomStart:({chart,event})=>{if(event&&event.deltaY!=null&&event.deltaY>0)return false;}},limits:{x:{min:-0.5,max:n-0.5,minRange:1,maxRange:__curRange}}}}:{};
  const __color='#2dbd8f';const ctx2d=canvas.getContext('2d');const grad=ctx2d.createLinearGradient(0,0,0,canvas.height||220);grad.addColorStop(0,__color+'66');grad.addColorStop(1,__color+'00');
  mainChart=new Chart(canvas,{type:'line',data:{labels,datasets:[{data:d.values,borderColor:__color,backgroundColor:grad,fill:true,tension:0.4,cubicInterpolationMode:'monotone',borderWidth:2.5,pointRadius:3,pointHoverRadius:6,pointBackgroundColor:__color,pointBorderColor:'#fff',pointBorderWidth:1.5,spanGaps:true}]},options:{responsive:true,maintainAspectRatio:false,devicePixelRatio:Math.min(window.devicePixelRatio||1,2),animation:false,transitions:{zoom:{animation:{duration:0}},pan:{animation:{duration:0}},active:{animation:{duration:0}},show:{animation:{duration:0}},hide:{animation:{duration:0}}},interaction:{mode:'nearest',intersect:false,axis:'x'},plugins:Object.assign({legend:{display:false},decimation:{enabled:true,algorithm:'lttb',samples:80},tooltip:{animation:false,displayColors:false,padding:10,titleFont:{size:12,weight:'600'},bodyFont:{size:12},callbacks:{title:items=>{if(!items||!items[0])return '';const i=items[0].dataIndex;const lab=__tlbl(d.labels[i]||'');const s=subs[i]||'';return s?lab+' · '+s:lab;},label:ctx=>currentMetric==='revenue'?' '+__money(ctx.raw,window.__bizSelSym?window.__bizSelSym():'£',window.__bizWalletCur):' '+ctx.raw+' pcs'}}},zoomOpts),scales:{x:{min:minIdx,max:maxIdx,grid:{display:false},ticks:{font:{size:11},color:'#5e5c58',maxRotation:0,autoSkip:true,maxTicksLimit:vis+1}},y:{beginAtZero:true,grace:'5%',grid:{color:'rgba(255,255,255,0.04)'},ticks:{font:{size:10},color:'#5e5c58',maxTicksLimit:5,callback:v=>currentMetric==='revenue'?__money(v,window.__bizSelSym?window.__bizSelSym():'£',window.__bizWalletCur):v}}}}});
}
function buildRingChart(){const a=analyticsData[currentPeriod];const total=a.ok+a.fail;const okPct=total>0?Math.round((a.ok/total)*100):0;const failPct=total>0?100-okPct:0;document.getElementById('ring-pct').textContent=okPct+'%';document.getElementById('leg-ok').textContent=a.ok.toLocaleString();document.getElementById('leg-fail').textContent=a.fail.toLocaleString();if(ringChart)ringChart.destroy();ringChart=new Chart(document.getElementById('ringChart'),{type:'doughnut',data:{datasets:[{data:total>0?[okPct,failPct]:[0,100],backgroundColor:total>0?['#2dbd8f','#6b2424']:['#2a2a2a','#2a2a2a'],borderWidth:0,hoverOffset:0}]},options:{cutout:'72%',responsive:false,plugins:{legend:{display:false},tooltip:{enabled:false}},animation:{duration:500}}});}
function switchMetric(m,el){currentMetric=m;document.querySelectorAll('.ctoggle').forEach(b=>b.classList.remove('active'));el.classList.add('active');buildMainChart();}
function switchPeriod(p,el){currentPeriod=p;document.querySelectorAll('.ptab').forEach(b=>b.classList.remove('active'));el.classList.add('active');buildMainChart();buildRingChart();}

/* Nav */
function goTo(pageId){document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));document.getElementById(pageId).classList.add('active');const navMap={'pg-home':'nav-home','pg-products':'nav-products','pg-orders':'nav-orders'};document.querySelectorAll('.nav-item').forEach(n=>{n.classList.remove('active');n.querySelectorAll('svg').forEach(s=>s.setAttribute('stroke','var(--color-text-secondary)'));n.querySelector('.nav-label').style.color='';});if(navMap[pageId]){const nav=document.getElementById(navMap[pageId]);nav.classList.add('active');nav.querySelectorAll('svg').forEach(s=>s.setAttribute('stroke','#2dbd8f'));nav.querySelector('.nav-label').style.color='#2dbd8f';}if(pageId==='pg-products'){renderProducts();renderPhotoGrid();}if(pageId==='pg-orders'){updateSummary();applyFilters();}if(pageId==='pg-notif')document.getElementById('notif-dot').style.display='none';}
function openMenu(){document.getElementById('menu-overlay').classList.add('open');document.body.style.overflow='hidden';document.documentElement.style.overflow='hidden';}
function closeMenu(){document.getElementById('menu-overlay').classList.remove('open');document.body.style.overflow='';document.documentElement.style.overflow='';}
function openPayout(){document.getElementById('payout-overlay').classList.add('open');}
function closePayout(){document.getElementById('payout-overlay').classList.remove('open');}

