 const BUSINESS={name:'Sunrise Kicks Ltd.',phone:'+44 20 1234 5678'};
 let photos=[],variantGroups=[],zones={},editingId=null,commMode='pct',currentCode='',variantIdCounter=0,groupIdCounter=0,selectedCurrency=null,currDropdownOpen=false,countryDropdownOpen=false,selectedCountry=null;
const genCode=()=>{const c='ABCDEFGHJKLMNPQRSTUVWXYZ23456789';let s='LT-';for(let i=0;i<6;i++)s+=c[Math.floor(Math.random()*c.length)];return s;};
