/* ── Backend bridge: map DB rows to the in-memory shape this UI expects ── */
function dbToProduct(r){const cur=r.currency?{...r.currency,symbol:__wrapArSym(r.currency.symbol,r.currency.code)}:null;return{id:r.id,code:r.code,bizName:r.biz_name||'',bizPhone:r.biz_phone||'',currency:cur,photos:r.photos||[],name:r.name,desc:r.description||'',price:Number(r.price)||0,commPct:Number(r.comm_pct)||0,commFixed:Number(r.comm_fixed)||0,commMode:r.comm_mode||'pct',platformFee:Number(r.platform_fee)||0,totalFeePerUnit:Number(r.total_fee_per_unit)||0,qty:Number(r.qty)||0,category:r.category||'',sizes:r.sizes||[],colors:r.colors||[],variantGroups:r.variant_groups||[],sold:Number(r.sold)||0,revenue:Number(r.revenue)||0,status:r.status||'active',delivery:r.delivery||{}};}
async function loadProducts(){if(!window.LateenAPI)return;try{const rows=await window.LateenAPI.listMyProducts();products=rows.map(dbToProduct);renderProducts();}catch(e){console.error('[Lateen] loadProducts',e);}}
let __unsubProducts=null;
function filterCurrencies(){const q=document.getElementById('curr-search').value.toLowerCase();const filtered=q?CURRENCIES.filter(c=>c.name.toLowerCase().includes(q)||c.code.toLowerCase().includes(q)||c.symbol.includes(q)):CURRENCIES;renderCurrencyDropdown(filtered);}
function renderCurrencyDropdown(list){document.getElementById('curr-dropdown').innerHTML=list.slice(0,200).map(c=>`<div class="currency-option" onclick="selectCurrency('${c.code}')"><span class="curr-flag">${c.flag}</span><span class="curr-label">${c.name}</span><span class="curr-sub">${c.code} · ${c.symbol}</span></div>`).join('');}
function toggleCurrencyDropdown(){currDropdownOpen=!currDropdownOpen;document.getElementById('curr-dropdown').classList.toggle('open',currDropdownOpen);document.getElementById('curr-search-wrap').style.display=currDropdownOpen?'block':'none';if(currDropdownOpen){renderCurrencyDropdown(CURRENCIES);setTimeout(()=>document.getElementById('curr-search').focus(),50);}}
function selectCurrency(code){selectedCurrency=CURRENCIES.find(c=>c.code===code);document.getElementById('curr-flag').textContent=selectedCurrency.flag;document.getElementById('curr-name').textContent=selectedCurrency.name+' ('+selectedCurrency.code+')';document.getElementById('curr-symbol-label').textContent=selectedCurrency.symbol;document.getElementById('price-prefix').textContent=selectedCurrency.symbol;document.getElementById('comm-curr-suffix').textContent=selectedCurrency.symbol;currDropdownOpen=false;document.getElementById('curr-dropdown').classList.remove('open');document.getElementById('curr-search-wrap').style.display='none';document.getElementById('curr-search').value='';updateFeeBreakdown();}
function calcFees(price,pct,fixedComm,mode){const comm=mode==='pct'?pctOf(price,pct):parseFloat(fixedComm||0);const platform=parseFloat((price*PLATFORM_FEE_RATE).toFixed(2));const total=parseFloat((comm+platform).toFixed(2));const commPct=mode==='pct'?pct:parseFloat(((comm/price)*100).toFixed(1));return{comm,platform,total,commPct};}
function updateFeeBreakdown(){const price=parseFloat(document.getElementById('f-price').value)||0;const pct=parseFloat(document.getElementById('f-comm-pct').value)||0;const fixed=parseFloat(document.getElementById('f-comm-fixed').value)||0;const card=document.getElementById('fee-breakdown-card');if(!price||(!pct&&!fixed)){card.style.display='none';return;}const{comm,platform,total,commPct}=calcFees(price,pct,fixed,commMode);const sym=selectedCurrency?selectedCurrency.symbol:'';document.getElementById('fbc-total').textContent=__money(total,sym,selectedCurrency&&selectedCurrency.code);document.getElementById('fbc-sub').textContent=`per unit · marketer ${__money(comm,sym,selectedCurrency&&selectedCurrency.code)} + platform ${__money(platform,sym,selectedCurrency&&selectedCurrency.code)}`;document.getElementById('fbc-comm').textContent=`${__money(comm,sym,selectedCurrency&&selectedCurrency.code)} (${commPct}%)`;document.getElementById('fbc-platform').textContent=__money(platform,sym,selectedCurrency&&selectedCurrency.code);card.style.display='block';}
function onPriceChange(){const price=parseFloat(document.getElementById('f-price').value)||0;if(commMode==='pct'){const pct=parseFloat(document.getElementById('f-comm-pct').value)||0;if(pct)document.getElementById('f-comm-fixed').value=pctOf(price,pct);}else{const fixed=parseFloat(document.getElementById('f-comm-fixed').value)||0;if(price&&fixed)document.getElementById('f-comm-pct').value=((fixed/price)*100).toFixed(1);}updateFeeBreakdown();}
function onCommPctChange(){const price=parseFloat(document.getElementById('f-price').value)||0;const pct=parseFloat(document.getElementById('f-comm-pct').value)||0;if(price&&pct)document.getElementById('f-comm-fixed').value=pctOf(price,pct);updateFeeBreakdown();}
function onCommFixedChange(){const price=parseFloat(document.getElementById('f-price').value)||0;const fixed=parseFloat(document.getElementById('f-comm-fixed').value)||0;if(price&&fixed)document.getElementById('f-comm-pct').value=((fixed/price)*100).toFixed(1);updateFeeBreakdown();}
function setCommMode(mode){commMode=mode;document.getElementById('mode-pct').classList.toggle('active',mode==='pct');document.getElementById('mode-fixed').classList.toggle('active',mode==='fixed');document.getElementById('f-comm-pct').disabled=mode==='fixed';document.getElementById('f-comm-fixed').disabled=mode==='pct';document.getElementById('f-comm-pct').style.opacity=mode==='fixed'?'0.4':'1';document.getElementById('f-comm-fixed').style.opacity=mode==='pct'?'0.4':'1';updateFeeBreakdown();}
function refreshCode(){currentCode=genCode();document.getElementById('product-code-display').textContent=currentCode;}
function onPhotosSelected(input){const files=Array.from(input.files);input.value='';(async()=>{for(const file of files){if(photos.length>=6)break;try{if(window.LateenAPI&&window.LateenAPI.uploadPhoto){const url=await window.LateenAPI.uploadPhoto(file);photos.push(url);}else{const url=await new Promise((res,rej)=>{const r=new FileReader();r.onload=e=>res(e.target.result);r.onerror=rej;r.readAsDataURL(file);});photos.push(url);}renderPhotoGrid();}catch(e){console.error('[Lateen] uploadPhoto',e);alert('Photo upload failed.');}}})();}
function removePhoto(i){photos.splice(i,1);renderPhotoGrid();}
function renderPhotoGrid(){const g=document.getElementById('photo-grid');if(!g)return;g.innerHTML=photos.map((src,i)=>`<div class="photo-preview"><img src="${src}"/><button class="photo-remove" onclick="removePhoto(${i})">×</button></div>`).join('')+(photos.length<6?`<div class="add-photo-btn" onclick="document.getElementById('photo-input').click()"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="var(--color-text-secondary)" stroke-width="1.6" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg><div class="add-photo-label">Add photo</div></div>`:'');}
function addVariantGroup(){variantGroups.push({id:groupIdCounter++,name:'Variant',items:[]});renderVariantGroups();setTimeout(()=>{const ins=document.querySelectorAll('.vg-name-input');if(ins.length)ins[ins.length-1].focus();},50);}
function removeVariantGroup(gid){variantGroups=variantGroups.filter(g=>g.id!==gid);renderVariantGroups();}
function renameVariantGroup(gid,name){const g=variantGroups.find(x=>x.id===gid);if(g)g.name=name;}
function addVariant(gid){const g=variantGroups.find(x=>x.id===gid);if(!g)return;g.items.push({id:variantIdCounter++,val:''});renderVariantGroups();setTimeout(()=>{const ins=document.querySelectorAll(`#vg-list-${gid} input`);if(ins.length)ins[ins.length-1].focus();},50);}
function removeVariant(gid,id){const g=variantGroups.find(x=>x.id===gid);if(g){g.items=g.items.filter(x=>x.id!==id);renderVariantGroups();}}
function updateVariant(gid,id,val){const g=variantGroups.find(x=>x.id===gid);if(!g)return;const it=g.items.find(x=>x.id===id);if(it)it.val=val;}
function renderVariantGroups(){const el=document.getElementById('variant-groups-container');if(!el)return;if(!variantGroups.length){el.innerHTML='<div class="vb-empty" style="border:0.5px dashed var(--color-border-secondary);border-radius:12px;margin-bottom:12px">No variants. Tap "Add another variant" below.</div>';return;}el.innerHTML=variantGroups.map(g=>{const ph=/colou?r|اللون|لون/i.test(g.name)?(__ar()?'مثال: أسود أو كحلي':'e.g. Black or Navy Blue'):/size|مقاس/i.test(g.name)?(__ar()?'مثال: 38 أو M أو XL':'e.g. 38 or M or XL'):(__ar()?'مثال: قيمة':'e.g. value');return`<div class="variant-builder"><div class="vb-header"><input class="vg-name-input" type="text" value="${g.name.replace(/"/g,'&quot;')}" oninput="renameVariantGroup(${g.id},this.value)" placeholder="Variant name"/><div style="display:flex;gap:6px;align-items:center"><button class="vb-add-btn" onclick="addVariant(${g.id})">+ Add value</button><button class="vg-remove-btn" onclick="removeVariantGroup(${g.id})" title="Remove group">×</button></div></div><div id="vg-list-${g.id}">${g.items.length?g.items.map(it=>`<div class="vb-item"><input type="text" value="${(it.val||'').replace(/"/g,'&quot;')}" placeholder="${ph}" oninput="updateVariant(${g.id},${it.id},this.value)" onkeydown="if(event.key==='Enter'){event.preventDefault();addVariant(${g.id});}"/><button class="vb-remove" onclick="removeVariant(${g.id},${it.id})">×</button></div>`).join(''):'<div class="vb-empty">Skip if not applicable</div>'}</div></div>`;}).join('');}
function filterCountries(){const q=document.getElementById('country-search').value.toLowerCase();const filtered=q?COUNTRIES.filter(c=>c.name.toLowerCase().includes(q)||c.code.toLowerCase().includes(q)):COUNTRIES;renderCountryDropdown(filtered);}
function renderCountryDropdown(list){document.getElementById('country-dropdown').innerHTML=list.slice(0,250).map(c=>`<div class="currency-option" onclick="selectCountry('${c.code}')"><span class="curr-flag">${c.flag}</span><span class="curr-label">${c.name}</span><span class="curr-sub">${c.code}</span></div>`).join('')||'<div class="vb-empty">No matches</div>';}
function toggleCountryDropdown(){countryDropdownOpen=!countryDropdownOpen;document.getElementById('country-dropdown').classList.toggle('open',countryDropdownOpen);document.getElementById('country-search-wrap').style.display=countryDropdownOpen?'block':'none';if(countryDropdownOpen){renderCountryDropdown(COUNTRIES);setTimeout(()=>document.getElementById('country-search').focus(),50);}}
function selectCountry(code){selectedCountry=COUNTRIES.find(c=>c.code===code);document.getElementById('country-flag').textContent=selectedCountry.flag;document.getElementById('country-name').textContent=selectedCountry.name+' ('+selectedCountry.code+')';countryDropdownOpen=false;document.getElementById('country-dropdown').classList.remove('open');document.getElementById('country-search-wrap').style.display='none';document.getElementById('country-search').value='';}
function addZone(){if(!selectedCountry||zones[selectedCountry.code])return;zones[selectedCountry.code]={cities:{}};selectedCountry=null;document.getElementById('country-flag').textContent='🌐';document.getElementById('country-name').textContent='Select a country';renderZoneBuilderList();}
function removeZone(code){delete zones[code];renderZoneBuilderList();}
function addCity(code){const id='new-city-'+code;const city=document.getElementById(id).value.trim();if(!city||zones[code].cities[city])return;zones[code].cities[city]={shipping:'',delivery:''};document.getElementById(id).value='';renderZoneBuilderList();}
function removeCity(code,city){delete zones[code].cities[city];renderZoneBuilderList();}
function updateCityCost(code,city,field,val){if(zones[code]&&zones[code].cities[city])zones[code].cities[city][field]=parseFloat(val)||0;}
function renderZoneBuilderList(){const el=document.getElementById('zone-builder-list');const keys=Object.keys(zones);if(!keys.length){el.innerHTML='';return;}el.innerHTML=keys.map(code=>{const z=zones[code];const ck=Object.keys(z.cities);return`<div class="zone-builder-card"><div class="zbc-header"><span class="zbc-country">${COUNTRY_NAMES[code]||code}</span><button class="zbc-remove" onclick="removeZone('${code}')">Remove</button></div>${ck.length?`<div class="city-row-labels"><span class="city-row-label">City</span><span class="city-row-label">Shipping</span><span class="city-row-label">Delivery</span><span></span></div>`:''}${ck.map(city=>`<div class="city-row"><input type="text" value="${city}" readonly/><input type="number" value="${z.cities[city].shipping||''}" placeholder="0.00" step="0.01" onchange="updateCityCost('${code}','${city}','shipping',this.value)"/><input type="number" value="${z.cities[city].delivery||''}" placeholder="0.00" step="0.01" onchange="updateCityCost('${code}','${city}','delivery',this.value)"/><button class="city-remove-btn" onclick="removeCity('${code}','${city}')">×</button></div>`).join('')}${!ck.length?`<div style="font-size:12px;color:var(--color-text-tertiary);padding:10px 12px">No cities yet</div>`:''}<div style="display:flex;gap:6px;padding:0 12px 10px"><input id="new-city-${code}" type="text" placeholder="Add a city…" style="flex:1;padding:7px 10px;font-size:12px;border:0.5px solid var(--color-border-secondary);border-radius:8px;background:var(--color-background-primary);color:var(--color-text-primary);outline:none;font-family:var(--font-sans);" onkeydown="if(event.key==='Enter'){event.preventDefault();addCity('${code}');}"/><button onclick="addCity('${code}')" style="height:34px;padding:0 12px;border-radius:8px;border:none;background:#2dbd8f;color:#fff;font-size:12px;font-weight:500;cursor:pointer;font-family:var(--font-sans);">Add</button></div></div>`;}).join('');}
function hydrateVariantGroups(p){const __sz=__ar()?'المقاسات':'Sizes';const __cl=__ar()?'الألوان':'Colours';if(!p)return[{id:groupIdCounter++,name:__sz,items:[]},{id:groupIdCounter++,name:__cl,items:[]}];if(p.variantGroups&&p.variantGroups.length)return p.variantGroups.map(g=>({id:groupIdCounter++,name:g.name,items:(g.items||[]).map(v=>({id:variantIdCounter++,val:v}))}));const out=[];out.push({id:groupIdCounter++,name:__sz,items:(p.sizes||[]).map(v=>({id:variantIdCounter++,val:v}))});out.push({id:groupIdCounter++,name:__cl,items:(p.colors||[]).map(v=>({id:variantIdCounter++,val:v}))});return out;}
function openAddForm(p){photos=p?[...(p.photos||[])]:[];variantGroups=hydrateVariantGroups(p);zones=p?JSON.parse(JSON.stringify(p.delivery)):{};commMode=p?.commMode||'pct';selectedCurrency=p?.currency||null;selectedCountry=null;currentCode=p?.code||genCode();document.getElementById('product-code-display').textContent=currentCode;document.getElementById('form-title').textContent=p?'Edit product':'Add a product';document.getElementById('f-name').value=p?.name||'';document.getElementById('f-desc').value=p?.desc||'';document.getElementById('f-price').value=p?.price||'';document.getElementById('f-qty').value=p?.qty||'';document.getElementById('f-category').value=p?.category||'';document.getElementById('f-comm-pct').value=p?.commPct||'';document.getElementById('f-comm-fixed').value=p?.commFixed||'';if(selectedCurrency){document.getElementById('curr-flag').textContent=selectedCurrency.flag;document.getElementById('curr-name').textContent=selectedCurrency.name+' ('+selectedCurrency.code+')';document.getElementById('curr-symbol-label').textContent=selectedCurrency.symbol;document.getElementById('price-prefix').textContent=selectedCurrency.symbol;document.getElementById('comm-curr-suffix').textContent=selectedCurrency.symbol;}else{document.getElementById('curr-flag').textContent='🌐';document.getElementById('curr-name').textContent='Select a currency';document.getElementById('curr-symbol-label').textContent='';document.getElementById('price-prefix').textContent='—';document.getElementById('comm-curr-suffix').textContent='—';}document.getElementById('country-flag').textContent='🌐';document.getElementById('country-name').textContent='Select a country';setCommMode(commMode);if(p)updateFeeBreakdown();else document.getElementById('fee-breakdown-card').style.display='none';renderPhotoGrid();renderVariantGroups();renderZoneBuilderList();document.getElementById('form-overlay').classList.add('open');}
