async function submitProduct(){const name=document.getElementById('f-name').value.trim();const price=parseFloat(document.getElementById('f-price').value)||0;const qty=parseInt(document.getElementById('f-qty').value)||0;const commPct=parseFloat(document.getElementById('f-comm-pct').value)||0;const commFixed=parseFloat(document.getElementById('f-comm-fixed').value)||0;console.log('[Lateen] submitProduct fired',{name,price,qty,commPct,commFixed,selectedCurrency,zones});if(!name||!price||(!commPct&&!commFixed)){alert('Please fill in name, price and commission.');return;}if(!selectedCurrency){alert('Please select a currency.');return;}if(!Object.keys(zones).length){alert('Please add at least one delivery zone.');return;}const validZones={};for(const[code,z]of Object.entries(zones)){const vc={};for(const[city,costs]of Object.entries(z.cities))if(costs.shipping&&costs.delivery)vc[city]=costs;if(Object.keys(vc).length)validZones[code]={cities:vc};}if(!Object.keys(validZones).length){alert('Please complete at least one city.');return;}const{comm,platform,total,commPct:finalPct}=calcFees(price,commPct,commFixed,commMode);const cleanGroups=variantGroups.map(g=>({name:(g.name||'Variant').trim()||'Variant',items:g.items.map(x=>x.val.trim()).filter(Boolean)})).filter(g=>g.items.length);const sizesGroup=cleanGroups.find(g=>/size/i.test(g.name));const colorsGroup=cleanGroups.find(g=>/colou?r/i.test(g.name));const payload={code:currentCode,name,description:document.getElementById('f-desc').value.trim(),category:document.getElementById('f-category').value,price,qty,currency:selectedCurrency,comm_pct:finalPct,comm_fixed:comm,comm_mode:commMode,platform_fee:platform,total_fee_per_unit:total,variant_groups:cleanGroups,sizes:sizesGroup?sizesGroup.items:[],colors:colorsGroup?colorsGroup.items:[],delivery:validZones,photos:[...photos],biz_name:(typeof BUSINESS!=='undefined'?BUSINESS.name:null),biz_phone:(typeof BUSINESS!=='undefined'?BUSINESS.phone:null)};if(editingId)payload.id=editingId;console.log('[Lateen] payload ready',payload);try{await window.LateenAPI.upsertProduct(payload);closeForm();await loadProducts();}catch(e){console.error('[Lateen] upsertProduct',e);alert('Could not save product: '+(e.message||e));}}
