function renderProducts(){const el=document.getElementById('product-list');if(!el)return;if(!products.length){el.innerHTML='<div class="empty-state">No products yet.</div>';return;}el.innerHTML=products.map(p=>{const ck=Object.keys(p.delivery);const allCities=ck.flatMap(c=>Object.keys(p.delivery[c].cities));const mainPhoto=p.photos&&p.photos.length?p.photos[0]:null;const lowStock=p.qty>0&&p.qty<=20;const sym=p.currency?__wrapArSym(p.currency.symbol,p.currency.code):'';const earnLabel=p.commMode==='fixed'?__money(p.commFixed,sym,p.currency&&p.currency.code):`${p.commPct}%`;const fmtP=n=>__money(n,sym,p.currency&&p.currency.code);return`<div class="product-card" id="card-${p.id}"><div class="pc-header" onclick="toggleCard('${p.id}')"><div class="pc-thumb">${mainPhoto?`<img src="${mainPhoto}" alt="${p.name}"/>`:p.currency?p.currency.flag:'📦'}</div><div style="flex:1;min-width:0"><div class="pc-name">${p.name}</div><div class="pc-code">${p.code} · ${p.currency?p.currency.code:''}</div><div class="pc-meta">${fmtP(p.price)} · ${earnLabel} commission · ${allCities.length} cities</div></div><div class="pc-right"><div class="pc-revenue">${fmtP(p.revenue)}</div><span class="sp ${lowStock?'sp-low':p.status==='active'?'sp-active':'sp-paused'}">${lowStock?'Low stock':p.status}</span></div><svg class="pc-chevron" id="chev-${p.id}" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="9 18 15 12 9 6"/></svg></div><div class="pc-body" id="body-${p.id}">${p.photos&&p.photos.length>1?`<div class="photo-strip-p">${p.photos.map(s=>`<img class="photo-thumb" src="${s}"/>`).join('')}</div>`:''}<div class="pc-stats"><div class="pc-stat"><div class="pc-stat-label">Sold</div><div class="pc-stat-value">${p.sold.toLocaleString()}</div></div><div class="pc-stat"><div class="pc-stat-label">In stock</div><div class="pc-stat-value" style="${p.qty<=20&&p.qty>0?'color:#c9923a':''}">${p.qty}</div></div><div class="pc-stat"><div class="pc-stat-label">Revenue</div><div class="pc-stat-value">${fmtP(p.revenue)}</div></div><div class="pc-stat"><div class="pc-stat-label">Fee/unit</div><div class="pc-stat-value" style="color:#8b83e8">${fmtP(p.totalFeePerUnit)}</div></div></div>${p.currency?`<div style="background:var(--color-background-secondary);border-radius:10px;padding:9px 12px;margin-bottom:14px;font-size:12px;display:flex;align-items:center;gap:8px;"><span style="font-size:16px">${p.currency.flag}</span><span style="font-weight:500;color:var(--color-text-primary)">${p.currency.name}</span><span style="color:var(--color-text-secondary);margin-left:auto">${p.currency.code} · ${p.currency.symbol}</span></div>`:''}${(()=>{const groups=p.variantGroups&&p.variantGroups.length?p.variantGroups:[...(p.sizes&&p.sizes.length?[{name:'Size',items:p.sizes}]:[]),...(p.colors&&p.colors.length?[{name:'Colour',items:p.colors}]:[])];if(!groups.length)return '';return `<div class="zones-title">Variants</div><div class="variants-row">${groups.map((g,gi)=>g.items.map(v=>`<span class="variant-chip" style="${gi%2?'background:#1a3d2f;color:#2dbd8f':''}">${g.name}: ${v}</span>`).join('')).join('')}</div>`;})()}<div class="zones-title">Delivery by city</div>${ck.map(code=>{const z=p.delivery[code];return`<div class="zone-block"><div class="zone-block-header">${COUNTRY_NAMES[code]||code}</div>${Object.entries(z.cities).map(([city,costs])=>`<div class="zone-city-row"><div class="zone-city-name">${city}</div><div class="zone-city-costs">Ship <span>${fmtP(costs.shipping)}</span> · Deliv <span>${fmtP(costs.delivery)}</span></div></div>`).join('')}</div>`;}).join('')}<div class="pc-actions"><button class="pc-action-btn" onclick="editProduct('${p.id}')">✏ Edit</button><button class="pc-action-btn pause" onclick="toggleStatus('${p.id}')">${p.status==='active'?'Pause':'Activate'}</button><button class="pc-action-btn del" onclick="deleteProduct('${p.id}')">🗑 Delete</button></div></div></div>`;}).join('');}

/* Orders */
const ST={new:{label:'New order',step:0,dot:'#E24B4A'},confirmed:{label:'Confirmed',step:1,dot:'#EF9F27'},delivered:{label:'Delivered',step:2,dot:'#2dbd8f'},failed:{label:'Failed',step:-1,dot:'#e07070'}};
const STEPS=['New','Confirmed','Delivered'];
const fmt=(n,sym,code)=>__money(n,sym,code);
let activeFilter='all',expandedId=null;
let orders=[];
function dbStatusToUi(s){return s==='confirmed'?'confirmed':s==='delivered'?'delivered':s==='cancelled'?'failed':'new';}
function dbToOrder(r){const curCode=(r.currency&&r.currency.code)||'GBP';const sym=__wrapArSym((r.currency&&r.currency.symbol)||'£',curCode);const prod=products.find(p=>p.id===r.product_id);const ph=prod&&prod.photos&&prod.photos.length?prod.photos:[(prod&&prod.currency&&prod.currency.flag)||'📦'];const dt=new Date(r.created_at);const d=dt.getDate()+' '+dt.toLocaleString('en',{month:'short'})+' '+dt.getFullYear();const q=Number(r.qty)||1;const shipping=Number(r.shipping_fee)||0;const delivery=Number(r.delivery_fee)||0;const total=Number(r.unit_price)*q+shipping+delivery;const mc=r.marketer_confirmed_at?new Date(r.marketer_confirmed_at):null;const mcDate=mc?(mc.getDate()+' '+mc.toLocaleString('en',{month:'short'})+' '+mc.getFullYear()):'';return{id:'#'+r.id.slice(0,8).toUpperCase(),dbId:r.id,marketerId:r.marketer_id||'',source:'affiliate',paymentType:'upfront',paymentAmount:Number(r.commission)*q+Number(r.platform_fee)*q,paymentDate:d,photos:ph,productEmoji:'📦',customerName:r.customer_name||'',customerPhone:r.customer_phone||'',customerWhatsapp:r.customer_whatsapp||'',country:r.customer_country||'',city:r.customer_city||'',address:r.customer_address||'',product:prod?prod.name:'(product)',productCode:prod?prod.code:'',sym,curCode,size:r.size||'',color:r.color||'',qty:q,price:Number(r.unit_price)||0,shipping,delivery,total,commission:Number(r.commission)*q,platformFee:Number(r.platform_fee)*q,status:dbStatusToUi(r.status),date:d,notes:r.customer_notes||'',receiptUrl:r.receipt_url||'',marketerConfirmed:!!r.marketer_confirmed_at,marketerConfirmedDate:mcDate,_createdAt:dt,_status:r.status};}
async function loadOrders(){if(!window.LateenAPI)return;try{const rows=await window.LateenAPI.listMyOrders();orders=rows.filter(r=>r.business_id).map(dbToOrder);updateSummary();applyFilters();recomputeAnalytics();}catch(e){console.error('[Lateen] loadOrders',e);if(!orders.length)renderOrders([]);}}
const __DOW=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
const __MON=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
function __buildSeries(){
  const now=new Date();const today=new Date(now.getFullYear(),now.getMonth(),now.getDate());
  let earliest=null;orders.forEach(o=>{const c=o._createdAt;if(c&&(!earliest||c<earliest))earliest=c;});
  const minDayStart=new Date(today);minDayStart.setDate(today.getDate()-29);
  let dayStart=earliest?new Date(earliest.getFullYear(),earliest.getMonth(),earliest.getDate()):new Date(today);
  if(dayStart>minDayStart)dayStart=minDayStart;
  const dayCount=Math.floor((today-dayStart)/86400000)+1;
  const minYear=now.getFullYear()-5;const startYear=earliest?Math.min(earliest.getFullYear(),minYear):minYear;
  const endYear=now.getFullYear();const yearCount=endYear-startYear+1;
  const monthsStart=new Date(startYear,0,1);const monthCount=(endYear-startYear)*12+now.getMonth()+1;
  const dayLabels=[],daySub=[];
  for(let i=0;i<dayCount;i++){const d=new Date(dayStart);d.setDate(dayStart.getDate()+i);dayLabels.push(__DOW[d.getDay()]);daySub.push(__ddmmyyyy(d));}
  const monLabels=[],monSub=[];
  for(let i=0;i<monthCount;i++){const m=new Date(monthsStart);m.setMonth(monthsStart.getMonth()+i);monLabels.push(__MON[m.getMonth()]);monSub.push(String(m.getFullYear()));}
  const yrLabels=[],yrSub=[];for(let i=0;i<yearCount;i++){yrLabels.push(String(startYear+i));yrSub.push('');}
  return{dayStart,dayCount,monthsStart,monthCount,startYear,yearCount,dayLabels,daySub,monLabels,monSub,yrLabels,yrSub};
}
function recomputeAnalytics(){
  const s=__buildSeries();
  const revD=Array(s.dayCount).fill(0),revM=Array(s.monthCount).fill(0),revY=Array(s.yearCount).fill(0);
  const pcsD=Array(s.dayCount).fill(0),pcsM=Array(s.monthCount).fill(0),pcsY=Array(s.yearCount).fill(0);
  const ringD={ok:0,fail:0},ringM={ok:0,fail:0},ringY={ok:0,fail:0};
  let totGross=0,totPieces=0,totOk=0,totFail=0,totComm=0,totPlat=0;const marketerSet=new Set();
  orders.forEach(o=>{
    const st=o._status;const c=o._createdAt;if(!c)return;
    const net=(o.price*o.qty)-o.commission-o.platformFee;
    const isOk=st==='delivered';const isFail=st==='cancelled'||st==='rejected';
    if(isOk){totGross+=o.price*o.qty;totPieces+=o.qty;totComm+=o.commission;totPlat+=o.platformFee;totOk++;if(o.marketerId)marketerSet.add(o.marketerId);}
    if(isFail)totFail++;
    const di=Math.floor((new Date(c.getFullYear(),c.getMonth(),c.getDate())-s.dayStart)/86400000);
    if(di>=0&&di<s.dayCount){if(isOk){revD[di]+=net;pcsD[di]+=o.qty;ringD.ok++;}if(isFail)ringD.fail++;}
    const mi=(c.getFullYear()-s.startYear)*12+c.getMonth();
    if(mi>=0&&mi<s.monthCount){if(isOk){revM[mi]+=net;pcsM[mi]+=o.qty;ringM.ok++;}if(isFail)ringM.fail++;}
    const yi=c.getFullYear()-s.startYear;
    if(yi>=0&&yi<s.yearCount){if(isOk){revY[yi]+=net;pcsY[yi]+=o.qty;ringY.ok++;}if(isFail)ringY.fail++;}
  });
  chartData.revenue.D={labels:s.dayLabels,sub:s.daySub,values:revD.map(v=>+v.toFixed(2))};
  chartData.revenue.M={labels:s.monLabels,sub:s.monSub,values:revM.map(v=>+v.toFixed(2))};
  chartData.revenue.Y={labels:s.yrLabels,sub:s.yrSub,values:revY.map(v=>+v.toFixed(2))};
  chartData.pieces.D={labels:s.dayLabels,sub:s.daySub,values:pcsD};
  chartData.pieces.M={labels:s.monLabels,sub:s.monSub,values:pcsM};
  chartData.pieces.Y={labels:s.yrLabels,sub:s.yrSub,values:pcsY};
  [['D',ringD],['M',ringM],['Y',ringY]].forEach(([k,r])=>{analyticsData[k]={ok:r.ok,fail:r.fail};});
  const set=(id,v)=>{const el=document.getElementById(id);if(el)el.textContent=v;};
  const totDone=totOk+totFail;
  set('stat-gross',__money(totGross,'£','GBP'));set('stat-pieces',totPieces.toLocaleString());set('stat-pieces-sub','across '+products.length+' products');set('stat-ok',totOk.toLocaleString());set('stat-ok-sub',totDone>0?Math.round(totOk/totDone*100)+'%':'0%');set('stat-fail',totFail.toLocaleString());set('stat-fail-sub',totDone>0?Math.round(totFail/totDone*100)+'%':'0%');set('stat-marketers',marketerSet.size.toLocaleString());set('brk-gross',__money(totGross,'£','GBP'));set('brk-comm','−'+__money(totComm,'£','GBP'));set('brk-plat','−'+__money(totPlat,'£','GBP'));set('brk-net',__money(totGross-totComm-totPlat,'£','GBP'));
  if(typeof buildMainChart==='function')buildMainChart();if(typeof buildRingChart==='function')buildRingChart();
}
function setFilter(f,el){activeFilter=f;document.querySelectorAll('.fchip').forEach(c=>c.classList.remove('active'));el.classList.add('active');applyFilters();}
function applyFilters(){const q=(document.getElementById('search-input')?document.getElementById('search-input').value||'':'').toLowerCase();const list=orders.filter(o=>{const mf=activeFilter==='all'||o.status===activeFilter;const mq=!q||o.id.toLowerCase().includes(q)||o.customerName.toLowerCase().includes(q)||o.city.toLowerCase().includes(q)||o.product.toLowerCase().includes(q);return mf&&mq;});renderOrders(list);}
function updateSummary(){const nc=orders.filter(o=>o.status==='new').length;const fc=orders.filter(o=>o.status==='failed').length;const st=document.getElementById('s-total');const sn=document.getElementById('s-new-sub');const ss=document.getElementById('s-ship');const sd=document.getElementById('s-done');if(st)st.textContent=orders.length;if(sn)sn.textContent=nc+' new';if(ss)ss.textContent=orders.filter(o=>o.status==='confirmed').length;if(sd)sd.textContent=orders.filter(o=>o.status==='delivered').length;const banner=document.getElementById('new-banner');if(banner)banner.style.display=nc>0?'flex':'none';const bt=document.getElementById('new-banner-text');if(bt)bt.textContent=nc+' new';const fcNew=document.getElementById('fc-new');if(fcNew)fcNew.innerHTML=nc>0?`New (${nc}) <span style="display:inline-block;width:5px;height:5px;border-radius:50%;background:#E24B4A;margin-left:3px;vertical-align:middle;animation:blink 1.5s infinite"></span>`:'New';const fcFailed=document.getElementById('fc-failed');if(fcFailed)fcFailed.textContent=fc>0?'Failed ('+fc+')':'Failed';}
async function advance(id,ns){const o=orders.find(x=>x.id===id);if(!o)return;if(ns==='failed'&&!confirm('Mark this order as failed? Stock will be restored. Marketer commission and platform fees are non-refundable.'))return;try{if(window.LateenAPI&&o.dbId){if(ns==='confirmed')await window.LateenAPI.confirmOrder(o.dbId);else if(ns==='delivered')await window.LateenAPI.markDelivered(o.dbId);else if(ns==='failed')await window.LateenAPI.markFailed(o.dbId);}}catch(e){console.error('[Lateen] advance',e);alert('Action failed: '+(e.message||e));return;}o.status=ns;o._status=ns==='failed'?'cancelled':ns;if(ns==='failed'){activeFilter='failed';expandedId=o.id;document.querySelectorAll('.fchip').forEach(c=>c.classList.remove('active'));const ff=document.getElementById('fc-failed');if(ff)ff.classList.add('active');}updateSummary();applyFilters();await loadProducts();await loadOrders();}
function buildStepper(s){if(s==='failed')return`<div style="font-size:12px;color:#e07070;font-weight:500;margin-bottom:12px">Order failed</div>`;const si=ST[s]?.step??0;let h='<div class="stepper">';STEPS.forEach((step,i)=>{const d=i<si,c=i===si;if(i>0)h+=`<div class="stp-line ${d?'done':''}"></div>`;h+=`<div class="stp"><div class="stp-dot ${d?'done':c?'cur':''}"></div><div class="stp-lbl ${d?'done':c?'cur':''}">${step}</div></div>`;});return h+'</div>';}
function buildActions(o){if(o.status==='delivered'||o.status==='failed')return`<div class="action-row"><button class="act a-lock" disabled>${o.status==='delivered'?'✓ Delivered':'Failed'}</button></div>`;let b='';if(o.status==='new')b+=`<button class="act a-confirm" onclick="event.stopPropagation();advance('${o.id}','confirmed')">Confirm order</button>`;if(o.status==='confirmed')b+=`<button class="act a-deliver" onclick="event.stopPropagation();advance('${o.id}','delivered')">Mark delivered</button>`;if(o.status==='new'||o.status==='confirmed')b+=`<button class="act a-fail" onclick="event.stopPropagation();advance('${o.id}','failed')">Failed</button>`;return`<div class="action-row">${b}</div>`;}
function renderOrders(list){const el=document.getElementById('orders-list');if(!el)return;if(!list.length){el.innerHTML='<div class="empty-state">No orders found.</div>';return;}el.innerHTML=list.map(o=>{const om=n=>fmt(n,o.sym,o.curCode);const st=ST[o.status]||ST.new;const isExp=expandedId===o.id;const isNew=o.status==='new';const ph=o.photos&&o.photos.length;const isImg=s=>typeof s==='string'&&/^(data:|https?:|\/)/.test(s);const photoEl=`<div class="prod-photo">${ph&&isImg(o.photos[0])?`<img src="${o.photos[0]}" alt="" loading="lazy"/>`:ph?o.photos[0]:o.productEmoji}</div>`;const strip=ph&&isExp?`<div class="photo-strip-o">${o.photos.map(p=>isImg(p)?`<div class="s-photo"><img src="${p}" alt="" loading="lazy"/></div>`:`<div class="s-photo">${p}</div>`).join('')}</div>`:'';const rightSide=`<div class="oc-amt">${om(o.total)}</div><div class="status-dot-row"><div class="status-dot" style="background:${st.dot};opacity:0.7"></div><span class="status-text">${st.label}</span></div>`;const newTag=isNew&&!isExp?`<div class="new-tag"><div class="nd"></div></div>`:'';const payLabel=o.paymentType==='upfront'?'Upfront fee paid':'Full payment received';const codBanner=o.paymentType==='upfront'?`<div style="display:flex;align-items:center;gap:10px;background:#3a2a10;border-radius:12px;padding:11px 14px;margin-bottom:12px;"><div style="width:32px;height:32px;border-radius:8px;background:#5a3e18;display:flex;align-items:center;justify-content:center;flex-shrink:0;"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#c9923a" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2z"/></svg></div><div><div style="font-size:13px;font-weight:500;color:#c9923a;">Cash on delivery</div><div style="font-size:11px;color:#9e7040;margin-top:1px;">Customer pays remaining balance on arrival</div></div></div>`:'';const inner=isExp?`<div class="oc-inner open">${strip}<div class="ipad">${buildStepper(o.status)}<div class="appr-note"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>${o.marketerConfirmed?'Marketer confirmed payment · '+o.marketerConfirmedDate:'Awaiting marketer confirmation · '+o.date}</div>${o.receiptUrl?`<a href="${o.receiptUrl}" target="_blank" rel="noopener" style="display:flex;align-items:center;gap:8px;background:#1a2a3a;border-radius:10px;padding:10px 12px;margin-bottom:12px;text-decoration:none;color:#7fb3e0;font-size:12px;font-weight:500"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>View payment receipt</a>`:''}<div class="pay-badge"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>${payLabel} · ${om(o.paymentAmount)} · ${o.paymentDate}</div>${codBanner}<div class="st">Customer &amp; delivery</div><div class="db"><div class="dr"><span class="dl">Name</span><span class="dv">${o.customerName}</span></div><div class="dr"><span class="dl">Phone</span><span class="dv">${o.customerPhone}</span></div>${o.customerWhatsapp?`<div class="dr"><span class="dl">WhatsApp</span><span class="dv">${o.customerWhatsapp}</span></div>`:''}<div class="dr"><span class="dl">Address</span><span class="dv">${o.address}</span></div><div class="dr"><span class="dl">City</span><span class="dv">${o.city}, ${o.country}</span></div></div><div class="st">Order</div><div class="db"><div class="dr"><span class="dl">Order ID</span><span class="dv mono">${o.id}</span></div><div class="dr"><span class="dl">Source</span><span class="dv">${o.source==='manual'?'Manual (marketer)':'Affiliate link'}</span></div><div class="dr"><span class="dl">Product</span><span class="dv">${o.product}</span></div><div class="dr"><span class="dl">Code</span><span class="dv mono">${o.productCode}</span></div>${o.size?`<div class="dr"><span class="dl">Size</span><span class="dv">${o.size}</span></div>`:''}${o.color?`<div class="dr"><span class="dl">Colour</span><span class="dv">${o.color}</span></div>`:''}<div class="dr"><span class="dl">Quantity</span><span class="dv">${o.qty}</span></div></div><div class="st">Financials</div><div class="fin-grid"><div class="fi"><div class="fi-l">Product price</div><div class="fi-v">${om(o.price)}</div></div><div class="fi"><div class="fi-l">Order total</div><div class="fi-v">${om(o.total)}</div></div><div class="fi"><div class="fi-l">Shipping</div><div class="fi-v">${om(o.shipping)}</div></div><div class="fi"><div class="fi-l">Delivery</div><div class="fi-v">${om(o.delivery)}</div></div><div class="fi"><div class="fi-l">Marketer comm.</div><div class="fi-v" style="color:#e07070">−${om(o.commission)}</div></div><div class="fi"><div class="fi-l">Platform fee</div><div class="fi-v" style="color:#e07070">−${om(o.platformFee)}</div></div></div>${o.notes?`<div class="st">Notes</div><div class="notes-box">${o.notes}</div>`:''}${buildActions(o)}</div></div>`:`<div class="oc-inner"></div>`;return`<div class="oc ${isNew?'is-new':''} ${isExp?'expanded':''}" onclick="toggle('${o.id}')">${newTag}<div class="oc-outer">${photoEl}<div class="oc-left"><div class="oc-cust">${o.customerName}</div><div class="oc-sub">${o.product} · ${o.city}, ${o.country}</div></div><div class="oc-right">${rightSide}</div><svg class="chevron ${isExp?'open':''}" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="9 18 15 12 9 6"/></svg></div>${inner}</div>`;}).join('');}
function toggle(id){expandedId=expandedId===id?null:id;applyFilters();}

recomputeAnalytics();

